class JoinStateEnumeratorTest {

	@Test
	void exhaustiveTopologyClosesCorrelatedPredicateOverDisconnectedPrefix() {
		JoinRegion region = new JoinRegion(
				List.of(new JoinFactor(1, 101), new JoinFactor(2, 102), new JoinFactor(3, 103)),
				List.of(),
				List.of(new JoinPredicate(0, new Bound(new Var("arm")), Set.of("arm"), List.of(999))));
		JoinSearchContext context = new JoinSearchContext(
				List.of(descriptor(1, 101, "arm"), descriptor(2, 102, "guard"),
						descriptor(3, 103, "tail")),
				Set.of(), PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);
		JoinSearchRequest request = JoinSearchRequest.enumeration(region, JoinSearchRequest.Mode.COMPLETE, 0L, 0L,
				context);
		JoinMemoEnumerationResult topology = new JoinSearchService(
				List.of(new ExhaustiveLegalJoinSearchContributor())).enumerateMemoExpressions(request, ignored -> {
				});

		assertTrue(topology.candidates()
				.stream()
				.map(JoinMemoExpressionCandidate::expression)
				.anyMatch(expression -> expression.resultOccurrenceIds().equals(Set.of(1, 3))),
				"The exhaustive contributor must enumerate the disconnected arm/tail subset");
		assertTrue(JoinStateEnumerator.enumerate(region, context, topology.candidates())
				.stream()
				.anyMatch(expression -> expression instanceof JoinStateExpression.ApplyPredicate application
						&& application.resultState().equals(new JoinState(Set.of(1, 3), Set.of(0)))),
				"Generic predicate closure must retain the correlated predicate over arm/tail");
	}

	@Test
	void extractedCorrelatedRegionClosesPredicateOverDisconnectedPrefix() {
		StatementPattern arm = pattern("arm");
		StatementPattern guard = pattern("guard");
		StatementPattern tail = pattern("tail");
		Filter root = new Filter(new Join(new Join(arm, guard), tail),
				new Not(new Exists(new StatementPattern(new Var("arm"), new Var("blockedPredicate"),
						new Var("block")))));
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		MemoJoinRegionExtractor.Result extraction = MemoJoinRegionExtractor.extract(memo, rootGroupId,
				rootExpression);

		assertTrue(extraction.supported(), () -> "Correlated filter extraction failed: " + extraction.boundaries());
		JoinRegion region = extraction.region();
		JoinSearchContext context = new JoinSearchContext(region.factors()
				.stream()
				.map(factor -> {
					MemoExpr factorExpression = memo.group(factor.groupId())
							.expressions()
							.stream()
							.filter(MemoExpr::logical)
							.findFirst()
							.orElseThrow();
					var shape = memo.group(factor.groupId()).bindingShape();
					return new JoinFactorDescriptor(factor.occurrenceId(), factor.groupId(),
							factorExpression.tupleExpr(), memo.universe(), shape.possible(), shape.assured(),
							region.requiredInputBindings(factor.occurrenceId()));
				})
				.toList(), memo.universe(), BindingMask.EMPTY, PhysicalProperties.ANY,
				OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);
		JoinSearchRequest request = JoinSearchRequest.enumeration(region, JoinSearchRequest.Mode.COMPLETE, 0L, 0L,
				context);
		JoinMemoEnumerationResult topology = new JoinSearchService(
				List.of(new ExhaustiveLegalJoinSearchContributor())).enumerateMemoExpressions(request, ignored -> {
				});

		Set<Integer> armTail = region.factors()
				.stream()
				.filter(factor -> {
					Set<String> names = memo.universe()
							.names(memo.group(factor.groupId()).bindingShape().possible());
					return names.contains("arm") || names.contains("tail");
				})
				.map(JoinFactor::occurrenceId)
				.collect(java.util.stream.Collectors.toUnmodifiableSet());
		assertTrue(JoinStateEnumerator.enumerate(region, context, topology.candidates())
				.stream()
				.anyMatch(expression -> expression instanceof JoinStateExpression.ApplyPredicate application
						&& application.resultState().occurrenceIds().equals(armTail)),
				"The exact extracted region must close its correlated predicate over arm/tail");
	}

	@Test
	void residualExistsConditionFallsBackToWholePredicateRegion() {
		StatementPattern arm = pattern("arm");
		StatementPattern guard = pattern("guard");
		Filter root = new Filter(new Join(arm, guard),
				new And(new Bound(new Var("guard")),
						new Not(new Exists(new StatementPattern(new Var("arm"), new Var("blockedPredicate"),
								new Var("block"))))));
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		int rootGroupId = memo.intern(root);
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();

		MemoJoinRegionExtractor.Result extraction = MemoJoinRegionExtractor.extract(memo, rootGroupId,
				rootExpression);

		assertTrue(extraction.supported(), () -> "Residual EXISTS fallback failed: " + extraction.boundaries());
		assertEquals(1, extraction.region().predicates().size());
		assertEquals(Set.of("arm", "guard"), extraction.region().predicates().getFirst().requiredBindingNames());
		assertTrue(extraction.region().predicates().getFirst().conditionTemplate() instanceof And,
				"Fallback must retain the complete scalar condition rather than extracting only EXISTS");
	}

	private static JoinFactorDescriptor descriptor(int occurrenceId, int groupId, String binding) {
		StatementPattern pattern = pattern(binding);
		return new JoinFactorDescriptor(occurrenceId, groupId, pattern, pattern.getBindingNames(),
				pattern.getBindingNames(), Set.of());
	}

	private static StatementPattern pattern(String binding) {
		return new StatementPattern(new Var(binding), new Var(binding + "Predicate"),
				new Var(binding + "Value"));
	}
}
